example.code:
{
  "$schema": "https://design-tokens.org/schema.json",
  "color": {
    "primitive": {
      "blue-500": {
        "$type": "color",
        "$value": "#3B82F6",
        "$description": "Raw blue value, not for direct use in components."
      }
    },
    "brand": {
      "primary": {
        "$type": "color",
        "$value": "{color.primitive.blue-500}",
        "$description": "Primary brand color for CTAs and interactive elements."
      }
    }
  },
  "spacing": {
    "base": {
      "$type": "dimension",
      "$value": "4px"
    },
    "component": {
      "button": {
        "$type": "dimension",
        "$value": "{spacing.base}",
        "$description": "Standard button padding unit."
      }
    }
  }
}
